"""
This module contains the Board class that manages the 8x8 checkers board.
"""

class Piece:
    def __init__(self, color):
        self.color = color

class Board:
    def __init__(self):
        self.board = [[None for _ in range(8)] for _ in range(8)]
        self.setup_board()

    def setup_board(self):
        for row in range(3):
            for col in range((row + 1) % 2, 8, 2):
                self.board[row][col] = Piece("red")
        for row in range(5, 8):
            for col in range(row % 2, 8, 2):
                self.board[row][col] = Piece("black")

    def print_board(self):
        import colorama
        colorama.init()
        for i, row in enumerate(self.board):
            print(f"{8 - i}| ", end="")
            for cell in row:
                if cell:
                    if cell.color == "red":
                        print(colorama.Back.RED + "R" + colorama.Style.RESET_ALL, end=" ")
                    else:
                        print(colorama.Back.BLUE + "B" + colorama.Style.RESET_ALL, end=" ")
                else:
                    print(".", end=" ")
            print()
        print("  |a b c d e f g h")

# Example usage
if __name__ == "__main__":
    board = Board()
    board.print_board()
```

#### Game.py

```python
"""
This module contains the CheckersGame class that manages the game state.
"""

from .Board import Board, Piece

class Player:
    def __init__(self, color):
        self.color = color

class Move:
    def __init__(self, from_pos, to_pos):
        self.from_pos = from_pos
        self.to_pos = to_pos

class CheckersGame:
    def __init__(self):
        self.board = Board()
        self.current_player = Player("red")

    def switch_player(self):
        if self.current_player.color == "red":
            self.current_player = Player("black")
        else:
            self.current_player = Player("red")

    def is_valid_move(self, move):
        # Simplified validation (not all rules are covered)
        from_row, from_col = move.from_pos
        to_row, to_col = move.to_pos
        piece = self.board.board[from_row][from_col]
        if piece and piece.color == self.current_player.color:
            return True
        return False

    def make_move(self, move):
        if self.is_valid_move(move):
            from_row, from_col = move.from_pos
            to_row, to_col = move.to_pos
            self.board.board[to_row][to_col] = self.board.board[from_row][from_col]
            self.board.board[from_row][from_col] = None
            self.switch_player()

# Example usage
if __name__ == "__main__":
    game = CheckersGame()
    while True:
        game.board.print_board()
        move_input = input(f"{game.current_player.color} player's turn (e.g., 0a-1b): ")
        try:
            from_pos = int(move_input[0]), ord(move_input[2]) - ord('a')
            to_pos = int(move_input[3]), ord(move_input[5]) - ord('a')
            move = Move(from_pos, to_pos)
            game.make_move(move)
        except Exception as e:
            print("Invalid move. Please try again.")
```

